INSERT INTO `x2_questions` (`questionid`, `questiontype`, `question`, `questionuserid`, `questionusername`, `questionlastmodifyuser`, `questionselect`, `questionselectnumber`, `questionanswer`, `questiondescribe`, `questionknowsid`, `questioncreatetime`, `questionstatus`, `questionhtml`, `questionparent`, `questionsequence`, `questionlevel`, `questiondeler`, `questiondeltime`) VALUES
(9758, 1, '<p>TST</p>', 1, 'peadmin', '', '<p>TST</p>\r\n\r\n<p>TST</p>\r\n\r\n<p>TST</p>\r\n\r\n<p>TST</p>', 4, 'A', '', 'a:1:{i:0;a:2:{s:7:"knowsid";s:1:"1";s:5:"knows";s:15:"演示知识点";}}', 1761465980, 1, '', 0, 0, 1, '', 0),
(9759, 1, '关于容量瓶的使用，下列操作正确的是', 1, 'peadmin', '', '<p>A、容量瓶长期存放溶液</p><p>B、用浓硫酸溶解固体试剂后立即转移至容量瓶</p><p>C、容量瓶干燥后未冷却直接配制标准溶液</p><p>D、定容时用胶头滴管逐滴加入蒸馏水至凹液面最低处与刻度线相切</p>', 0, 'D', '容量瓶作为精密量器，使用时需注意：1. 不能长期储存溶液（A错误），应转移到试剂瓶中保存；2. 热溶液需冷却至室温再转移（B、C错误），否则体积不准确；3. 定容时需用胶头滴管精细调整液面（D正确），确保体积精确。', 'a:1:{i:0;a:2:{s:7:"knowsid";s:1:"1";s:5:"knows";s:15:"演示知识点";}}', 1761889379, 1, '', 0, 0, 1, '', 0),
(9760, 1, '关于容量瓶的使用方法，下列叙述正确的是', 1, 'peadmin', '', '<p>A、容量瓶可长期存放配制好的标准溶液</p><p>B、容量瓶可用烘箱在105℃下烘干</p><p>C、容量瓶可加热溶解固体试剂</p><p>D、定容时视线应与凹液面最低处水平</p>', 0, 'D', '容量瓶作为精密量器，使用时需注意：A错误，容量瓶不宜长期存放溶液，特别是碱性溶液会腐蚀瓶塞；B错误，容量瓶不能烘干，否则会导致体积变化；C错误，容量瓶不能加热或用于溶解操作；D正确，定容时视线应与凹液面最低处保持水平，以确保体积准确。', 'a:1:{i:0;a:2:{s:7:"knowsid";s:1:"2";s:5:"knows";s:16:"测试2知识点";}}', 1761889566, 1, '', 0, 0, 1, '', 0),
(9761, 3, '厂商上门维修,发现机房维修笔记本缺少维修使用软件,厂商工程师直接把软件发送给驻场人员,驻场人员直接将软件安装在维修电脑上', 0, '', '', '【A】正确 <br>【B】错误', 2, 'B', '', 'a:1:{i:0;a:2:{s:7:"knowsid";s:1:"1";s:5:"knows";s:15:"演示知识点";}}', 1762325816, 1, '', 0, 0, 1, '', 0),
(9762, 3, '掉电机柜空开跳闸,为尽快恢复机柜双路供电,驻场IT工程师直接对跳闸空开进行合闸', 0, '', '', '【A】正确 <br>【B】错误', 2, 'B', '', 'a:1:{i:0;a:2:{s:7:"knowsid";s:1:"1";s:5:"knows";s:15:"演示知识点";}}', 1762325816, 1, '', 0, 0, 1, '', 0),
(9763, 1, '1+1的电源冗余模式中，当其中一个电源模块发生故障无法输出功率时，另一个电源模块会？', 0, '', '', '【A】唤醒故障电源模块 <br>【B】承担全部输出功率 <br>【C】启动自我保护，停止输出功率 <br>【D】承担50%功率输出', 4, 'B', '1+1电源冗余正常工作是两个电源各承担50%功率，1个电源故障时，另一个电源承担所有功率负载', 'a:1:{i:0;a:2:{s:7:"knowsid";s:1:"1";s:5:"knows";s:15:"演示知识点";}}', 1762325816, 1, '', 0, 0, 1, '', 0),
(9764, 1, '5类双绞线（CAT5）的最高传输速率为', 0, '', '', '【A】100Mb/S <br>【B】155M/S <br>【C】250Mb/S <br>【D】600Mb/S', 4, 'A', '区分五类、超五类（CAT-5E）和六类线的传输速率。五类线最高频率带宽为100MHz，最高传输率为100Mbps，用于语音传输和最高传输速率为100Mbps的数据传输。', 'a:1:{i:0;a:2:{s:7:"knowsid";s:1:"1";s:5:"knows";s:15:"演示知识点";}}', 1762325816, 1, '', 0, 0, 1, '', 0),
(9765, 3, 'Aliserverpx04-j108机型JBOD带外网络问题排查,观察JBOD带外网口数据灯闪烁状态,状态灯常亮,表示带外口与上联带外交换机处于正常连接状态', 0, '', '', '【A】正确 <br>【B】错误', 2, 'A', '', 'a:1:{i:0;a:2:{s:7:"knowsid";s:1:"1";s:5:"knows";s:15:"演示知识点";}}', 1762325816, 1, '', 0, 0, 1, '', 0),
(9766, 3, '厂商上门维修,发现机房维修笔记本缺少维修使用软件,厂商工程师直接把软件发送给驻场人员,驻场人员直接将软件安装在维修电脑上', 0, '', '', '【A】正确 <br>【B】错误', 2, 'B', '', 'a:1:{i:0;a:2:{s:7:"knowsid";s:1:"1";s:5:"knows";s:15:"演示知识点";}}', 1762325997, 1, '', 0, 0, 1, '', 0),
(9767, 3, '掉电机柜空开跳闸,为尽快恢复机柜双路供电,驻场IT工程师直接对跳闸空开进行合闸', 0, '', '', '【A】正确 <br>【B】错误', 2, 'B', '', 'a:1:{i:0;a:2:{s:7:"knowsid";s:1:"1";s:5:"knows";s:15:"演示知识点";}}', 1762325997, 1, '', 0, 0, 1, '', 0),
(9768, 1, '1+1的电源冗余模式中，当其中一个电源模块发生故障无法输出功率时，另一个电源模块会？', 0, '', '', '【A】唤醒故障电源模块 <br>【B】承担全部输出功率 <br>【C】启动自我保护，停止输出功率 <br>【D】承担50%功率输出', 4, 'B', '1+1电源冗余正常工作是两个电源各承担50%功率，1个电源故障时，另一个电源承担所有功率负载', 'a:1:{i:0;a:2:{s:7:"knowsid";s:1:"1";s:5:"knows";s:15:"演示知识点";}}', 1762325997, 1, '', 0, 0, 1, '', 0),
(9769, 1, '5类双绞线（CAT5）的最高传输速率为', 0, '', '', '【A】100Mb/S <br>【B】155M/S <br>【C】250Mb/S <br>【D】600Mb/S', 4, 'A', '区分五类、超五类（CAT-5E）和六类线的传输速率。五类线最高频率带宽为100MHz，最高传输率为100Mbps，用于语音传输和最高传输速率为100Mbps的数据传输。', 'a:1:{i:0;a:2:{s:7:"knowsid";s:1:"1";s:5:"knows";s:15:"演示知识点";}}', 1762325997, 1, '', 0, 0, 1, '', 0),
(9770, 3, 'Aliserverpx04-j108机型JBOD带外网络问题排查,观察JBOD带外网口数据灯闪烁状态,状态灯常亮,表示带外口与上联带外交换机处于正常连接状态', 0, '', '', '【A】正确 <br>【B】错误', 2, 'A', '', 'a:1:{i:0;a:2:{s:7:"knowsid";s:1:"1";s:5:"knows";s:15:"演示知识点";}}', 1762325997, 1, '', 0, 0, 1, '', 0);
